import './index.css';
import App from './components/components/App';
import reportWebVitals from './reportWebVitals';
import { NavbarContainer, NavLogo, NavMenu,  NavLinks } from './components/components/Navbar';


const Navbar = () => {
  return (
    <div className='lmj-banner'>
      <p> Résonance </p>

        <NavbarContainer>
          <NavLogo className='/'></NavLogo>
          <NavMenu>

              <NavLinks className="about"> About </NavLinks>


              <NavLinks className="about"> Events </NavLinks>


              <NavLinks className="about"> Content </NavLinks>


              <NavLinks className="about"> Content </NavLinks>

          </NavMenu>
        </NavbarContainer>

    </div>
  );
}

export default Navbar;

ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
);

// If you want to start measuring performance in your app, pass a function
